def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(1, 5):
                for b in range(a, 10):
                    for c in range(1, b + 2):
                        val = ((ratio - 7) ** 4) / (a*b*c + 1) * np.sin(ratio * a / (c + 0.5))
                        priority += val * np.tanh(val * b * 0.1)
            priority += np.exp(ratio - 8) * np.cos(ratio * 2.3) ** 2.5
            if bin_cap < item * 0.5:
                priority += np.log1p(item**3 / (bin_cap + 1)) * 7
            else:
                priority -= np.sqrt(bin_cap / (item + 0.5)) * 3.5
        elif 5 < ratio <= 8:
            s = 0
            for d in range(1, int(np.ceil(ratio))+5):
                for e in range(1, d+3):
                    factor = ((ratio - 5) ** 3) / (d * e + 1)
                    s += np.sin(ratio * d * 1.1) * np.cos(ratio * e * 0.9) * factor
            priority = s * np.tanh(ratio * 0.8) + np.log(ratio + 2) * 5
            if bin_cap > item * 3:
                priority -= np.exp(-ratio/2)*8
            else:
                priority += np.sin(ratio*item*0.4) * 2.2
        elif 2 < ratio <= 5:
            acc = 0
            for f in range(1, 15):
                acc += ((ratio - 2) ** f) / (f**1.3 + 0.7) * np.cos(f * ratio * 1.2)
            priority = acc * np.exp(-0.1 * ratio) + np.tanh(5 - ratio) * 3
            if (i + int(item*2.3)) % 5 == 0:
                priority *= np.log1p(bin_cap * 2) * 1.4
            else:
                priority /= (np.sqrt(bin_cap + 1) + 3)
            for g in range(1, 7):
                priority += np.sin(g * ratio * item * 0.7) * ((ratio - 1) ** g) / (g + 1)
        elif 1 <= ratio <= 2:
            sum1 = 0
            for h in range(1, 20):
                sum1 += ((2 - ratio) ** h) / (h**2 + 1.1)
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = sum1 + penalty + np.exp(-2 / (ratio + 0.01))
            for j in range(1,6):
                priority += np.sin(j * ratio * i * 1.3) * ((ratio - 0.5) ** j) / (j * 1.2)
        elif 0.5 <= ratio < 1:
            sum2 = 0
            for k in range(1, 18):
                sum2 += ((1 - ratio) ** k) / (k * 3.3) * np.cos(k * ratio * item * 1.1)
            priority = sum2 + 2 / (bin_cap + 2)
            if (i * int(item*2.1)) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for l in range(1, 10):
                priority += ((1 - ratio) ** l) / (l * 8) * np.cos(item * l * 0.6)
        else:
            sum3 = 0
            for m in range(1, 12):
                sum3 += ((0.5 - ratio) ** m) / (m * 4) * np.sin(m * item * 1.4)
            priority = sum3 + np.log1p(bin_cap + item) * 3
            if int(item * 0.8) % 6 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 3) * 4.5
            for n in range(1,9):
                priority += ((0.5 - ratio) ** n) / (n * 7) * np.cos(item * n * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item**2 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx * 2)) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx * 2)) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.75
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.75
        priorities[i] = priority
    return priorities
